import { NextResponse, type NextRequest } from "next/server"
import { firebaseAdminAuth } from "@/lib/firebase/admin"
import { SESSION_COOKIE_NAME } from "@/lib/firebase/server-auth"

const SESSION_MAX_AGE = 60 * 60 * 24 * 14 // 14 days

export async function POST(request: NextRequest) {
  try {
    const { idToken } = (await request.json()) as { idToken?: string }

    if (!idToken) {
      return NextResponse.json({ error: "Missing idToken" }, { status: 400 })
    }

    const decoded = await firebaseAdminAuth.verifyIdToken(idToken)

    const expiresIn = SESSION_MAX_AGE * 1000
    const sessionCookie = await firebaseAdminAuth.createSessionCookie(idToken, { expiresIn })

    const response = NextResponse.json({ success: true, uid: decoded.uid })

    response.cookies.set(SESSION_COOKIE_NAME, sessionCookie, {
      maxAge: SESSION_MAX_AGE,
      httpOnly: true,
      secure: process.env.NODE_ENV === "production",
      sameSite: "lax",
      path: "/",
    })

    return response
  } catch (error) {
    console.error("Error creating session cookie", error)
    return NextResponse.json({ error: "Failed to create session" }, { status: 500 })
  }
}

export async function DELETE() {
  const response = NextResponse.json({ success: true })

  response.cookies.set(SESSION_COOKIE_NAME, "", {
    maxAge: 0,
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "lax",
    path: "/",
  })

  return response
}
